package agentd

import (
	"context"
	"time"

	"sigs.k8s.io/controller-runtime/pkg/controller"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"

	"k8s.io/apimachinery/pkg/runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	ctrl "sigs.k8s.io/controller-runtime"
	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/klog/v2"
	agentkubeshv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
)

const LastActivityAnnotationKey = "last-activity-time"

var SessionExpirationTimeout = 15 * time.Minute

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	sandbox := &agentkubeshv1alpha1.Sandbox{}
	err := r.Get(ctx, req.NamespacedName, sandbox)
	if err != nil {
		if errors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	lastActivityStr, exists := sandbox.Annotations[LastActivityAnnotationKey]
	if exists && lastActivityStr != "" {
		lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
		if err != nil {
			klog.Errorf("Failed to parse last activity time %s: %v", lastActivityStr, err)
			return reconcile.Result{RequeueAfter: 30 * time.Second}, err
		}

		expirationTime := lastActivity.Add(SessionExpirationTimeout)
		if time.Now().After(expirationTime) {
			klog.Infof("Deleting expired sandbox %s/%s", req.Namespace, req.Name)
			if err := r.Delete(ctx, sandbox); err != nil {
				if errors.IsNotFound(err) {
					return reconcile.Result{}, nil
				}
				return reconcile.Result{}, err
			}
			return reconcile.Result{}, nil
		}

		return reconcile.Result{RequeueAfter: time.Until(expirationTime)}, nil
	}

	return reconcile.Result{}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&agentkubeshv1alpha1.Sandbox{}).
		Complete(r)
}

type idleCleanupController struct {
	client client.Client
	scheme *runtime.Scheme
}

func NewIdleCleanupController(cli client.Client, scheme *runtime.Scheme) *idleCleanupController {
	return &idleCleanupController{
		client: cli,
		scheme: scheme,
	}
}

func (c *idleCleanupController) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	return (&Reconciler{
		Client: c.client,
		Scheme: c.scheme,
	}).Reconcile(ctx, req)
}

func AddController(mgr ctrl.Manager) error {
	c, err := controller.New("agentd-controller", mgr, controller.Options{
		Reconciler: &Reconciler{
			Client: mgr.GetClient(),
			Scheme: mgr.GetScheme(),
		},
	})
	if err != nil {
		return err
	}

	return c.Watch(&agentkubeshv1alpha1.Sandbox{}, nil)
}

