package main

import (
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"errors"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

const (
	Version         = "0.0.1"
	DefaultTimeout  = 60 * time.Second
	TimeoutExitCode = 124
	MaxBodySize     = 10 * 1024 * 1024
)

type ExecuteRequest struct {
	Command    []string          `json:"command"`
	Timeout    string            `json:"timeout"`
	WorkingDir string            `json:"working_dir"`
	Env        map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string  `json:"stdout"`
	Stderr    string  `json:"stderr"`
	ExitCode  int     `json:"exit_code"`
	Duration  float64 `json:"duration"`
	StartTime string  `json:"start_time"`
	EndTime   string  `json:"end_time"`
}

type UploadFileRequest struct {
	Path    string `json:"path"`
	Content string `json:"content"`
	Mode    string `json:"mode"`
}

type FileInfo struct {
	Path string `json:"path"`
	Size int64  `json:"size"`
	Mode string `json:"mode"`
}

type FileEntry struct {
	Name     string `json:"name"`
	Size     int64  `json:"size"`
	Modified string `json:"modified"`
	Mode     string `json:"mode"`
	IsDir    bool   `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type Config struct {
	Port          int
	Workspace     string
	AuthPublicKey *rsa.PublicKey
}

type Server struct {
	config     *Config
	router     *gin.Engine
	startTime  time.Time
	httpServer *http.Server
}

func NewServer(config *Config) (*Server, error) {
	if config.Port <= 0 {
		config.Port = 8080
	}
	if config.Workspace == "" {
		cwd, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get current directory: %w", err)
		}
		config.Workspace = cwd
	}

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Recovery())
	router.Use(gin.Logger())

	srv := &Server{
		config:    config,
		router:    router,
		startTime: time.Now(),
		httpServer: &http.Server{
			Addr:              fmt.Sprintf(":%d", config.Port),
			Handler:           router,
			ReadHeaderTimeout: 10 * time.Second,
		},
	}

	srv.setupRoutes()
	return srv, nil
}

func (s *Server) setupRoutes() {
	s.router.GET("/health", s.handleHealth)

	api := s.router.Group("/api")
	api.Use(s.authMiddleware())
	api.POST("/execute", s.handleExecute)
	api.POST("/files", s.handleUploadFile)
	api.GET("/files", s.handleListFiles)
	api.GET("/files/*path", s.handleDownloadFile)
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "missing authorization header",
				"code":   401,
				"detail": "Authorization header is required",
			})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "invalid authorization header format",
				"code":   401,
				"detail": "Authorization header must be 'Bearer <token>'",
			})
			return
		}

		tokenString := parts[1]
		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return s.config.AuthPublicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(1*time.Minute))

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid token",
				"code":   401,
				"detail": err.Error(),
			})
			return
		}

		c.Next()
	}
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "PicoD",
		"version": Version,
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command cannot be empty", "code": 400})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("invalid timeout format: %s", req.Timeout),
				"code":  400,
			})
			return
		}
	}

	cmd := s.buildCommand(req)
	if req.WorkingDir != "" {
		dir, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid working directory: %s", err.Error()),
				"code":  400,
			})
			return
		}
		cmd.Dir = dir
	}

	startTime := time.Now()
	done := make(chan error, 1)
	var stdout, stderr strings.Builder
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	go func() {
		done <- cmd.Run()
	}()

	select {
	case err := <-done:
		exitCode := 0
		responseStderr := stderr.String()
		if err != nil {
			if exitErr, ok := err.(*exec.ExitError); ok {
				exitCode = exitErr.ExitCode()
			} else {
				exitCode = 1
			}
		}

		c.JSON(http.StatusOK, ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    responseStderr,
			ExitCode:  exitCode,
			Duration:  time.Since(startTime).Seconds(),
			StartTime: startTime.Format(time.RFC3339),
			EndTime:   time.Now().Format(time.RFC3339),
		})
	case <-time.After(timeout):
		cmd.Process.Kill()
		<-done
		c.JSON(http.StatusOK, ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    fmt.Sprintf("command timed out after %v", timeout),
			ExitCode:  TimeoutExitCode,
			Duration:  timeout.Seconds(),
			StartTime: startTime.Format(time.RFC3339),
			EndTime:   time.Now().Format(time.RFC3339),
		})
	}
}

func (s *Server) buildCommand(req ExecuteRequest) *exec.Cmd {
	cmd := exec.CommandContext(context.Background(), req.Command[0], req.Command[1:]...)
	if len(req.Env) > 0 {
		env := os.Environ()
		for k, v := range req.Env {
			env = append(env, fmt.Sprintf("%s=%s", k, v))
		}
		cmd.Env = env
	}
	return cmd
}

func (s *Server) handleUploadFile(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")
	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
		return
	}

	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	if req.Path == "" || req.Content == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path and content are required", "code": 400})
		return
	}

	data, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid base64 content", "code": 400})
		return
	}

	path, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Invalid path: %s", err.Error()), "code": 400})
		return
	}

	if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	mode := parseFileMode(req.Mode)
	if err := os.WriteFile(path, data, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	info, _ := os.Stat(path)
	c.JSON(http.StatusOK, FileInfo{
		Path: req.Path,
		Size: info.Size(),
		Mode: fmt.Sprintf("%04o", mode&0777),
	})
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	if err := c.Request.ParseMultipartForm(32 << 20); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	path := c.Request.PostFormValue("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required", "code": 400})
		return
	}

	file, _, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file is required", "code": 400})
		return
	}
	defer file.Close()

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Invalid path: %s", err.Error()), "code": 400})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	data, _ := io.ReadAll(file)
	mode := parseFileMode(c.Request.PostFormValue("mode"))
	if err := os.WriteFile(sanitizedPath, data, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	c.JSON(http.StatusOK, FileInfo{
		Path: path,
		Size: int64(len(data)),
		Mode: fmt.Sprintf("%04o", mode&0777),
	})
}

func (s *Server) handleListFiles(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Missing 'path' query parameter", "code": 400})
		return
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Invalid path: %s", err.Error()), "code": 400})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "Directory not found", "code": 404})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	var files []FileEntry
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime().Format(time.RFC3339),
			Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) handleDownloadFile(c *gin.Context) {
	path := c.Param("path")
	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Access denied: " + err.Error(), "code": 400})
		return
	}

	info, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "File not found", "code": 404})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Path is a directory, not a file", "code": 400})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(sanitizedPath)))
	c.Header("Content-Type", "application/octet-stream")
	c.File(sanitizedPath)
}

func (s *Server) sanitizePath(requestedPath string) (string, error) {
	if !strings.HasPrefix(requestedPath, "/") {
		requestedPath = filepath.Join(s.config.Workspace, requestedPath)
	}

	cleanPath := filepath.Clean(requestedPath)
	wsClean := filepath.Clean(s.config.Workspace)

	if !strings.HasPrefix(cleanPath, wsClean) {
		return "", errors.New("access denied: path outside workspace")
	}

	return cleanPath, nil
}

func parseFileMode(modeStr string) os.FileMode {
	mode := os.FileMode(0644)
	if modeStr != "" {
		var m int
		fmt.Sscanf(modeStr, "%o", &m)
		mode = os.FileMode(m)
	}
	if mode > 0777 {
		mode = 0644
	}
	return mode
}

func parsePublicKey(pemData string) (*rsa.PublicKey, error) {
	block, _ := pem.Decode([]byte(pemData))
	if block == nil {
		return nil, errors.New("failed to parse PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return nil, err
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return nil, errors.New("not an RSA public key")
	}

	return rsaPub, nil
}

func main() {
	port := 8080
	fmt.Sscanf(os.Getenv("PORT"), "%d", &port)

	workspace := os.Getenv("PICOD_WORKSPACE")

	publicKeyPEM := os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	if publicKeyPEM == "" {
		klog.Fatal("PICOD_AUTH_PUBLIC_KEY is required")
	}

	publicKey, err := parsePublicKey(publicKeyPEM)
	if err != nil {
		klog.Fatalf("Failed to parse public key: %v", err)
	}

	config := &Config{
		Port:          port,
		Workspace:     workspace,
		AuthPublicKey: publicKey,
	}

	srv, err := NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	klog.Infof("Starting PicoD on port %d", port)
	if err := srv.httpServer.ListenAndServe(); err != nil {
		klog.Errorf("Server error: %v", err)
	}
}

